void Graph::rebuild_ids() const {
    cached_ids_.clear();
    cached_ids_.reserve(nodes_.size());
    for (auto& [id, _] : nodes_) cached_ids_.push_back(id);
    std::sort(cached_ids_.begin(), cached_ids_.end());
