#include "test_framework.hpp"
#include "mst/mst.hpp"

using namespace cryo;
using namespace cryo_test;

namespace {

Graph make_graph(size_t n) {
    Graph g(GraphType::Undirected);
    for (size_t i = 0; i < n; i++) {
        g.add_node_with_id(i);
    }
    return g;
}

void assert_connected_mst_parity(const Graph& g) {
    auto km = kruskal(g);
    auto pm = prim(g, 0);
    auto bm = boruvka(g);

    assert_near(bm.total_weight, km.total_weight, 1e-9, "boruvka vs kruskal");
    assert_near(bm.total_weight, pm.total_weight, 1e-9, "boruvka vs prim");
    assert_true(is_spanning_tree(g, bm));
}

} // namespace

CRYO_TEST(MST, BoruvkaConsidersBothEndpointComponents) {
    auto g = make_graph(4);
    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 100.0);
    g.add_edge(1, 2, 2.0);
    g.add_edge(1, 3, 1.0);
    g.add_edge(2, 3, 50.0);

    auto bm = boruvka(g);

    assert_near(bm.total_weight, 4.0, 1e-9);
    assert_connected_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaEqualWeightEdges) {
    auto g = make_graph(4);
    g.add_edge(0, 1, 1.0);
    g.add_edge(0, 2, 1.0);
    g.add_edge(0, 3, 1.0);
    g.add_edge(1, 2, 1.0);
    g.add_edge(1, 3, 1.0);
    g.add_edge(2, 3, 1.0);

    auto bm = boruvka(g);

    assert_near(bm.total_weight, 3.0, 1e-9);
    assert_connected_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaMultipleComponentsMergeInPhase) {
    auto g = make_graph(6);
    g.add_edge(0, 1, 1.0);
    g.add_edge(1, 2, 2.0);
    g.add_edge(2, 3, 1.0);
    g.add_edge(3, 4, 2.0);
    g.add_edge(4, 5, 1.0);
    g.add_edge(0, 5, 10.0);
    g.add_edge(1, 4, 8.0);

    auto bm = boruvka(g);

    assert_eq(bm.edges.size(), static_cast<size_t>(5));
    assert_near(bm.total_weight, 7.0, 1e-9);
    assert_connected_mst_parity(g);
}

CRYO_TEST(MST, BoruvkaSingleNode) {
    auto g = make_graph(1);

    auto km = kruskal(g);
    auto pm = prim(g, 0);
    auto bm = boruvka(g);

    assert_true(bm.edges.empty());
    assert_false(bm.is_forest);
    assert_near(bm.total_weight, km.total_weight, 1e-9);
