    g.add_edge(0, 2, 10.0);
    g.add_edge(3, 4, 3.0);
    g.add_edge(4, 5, 4.0);
    g.add_edge(3, 5, 30.0);

    auto km = kruskal(g);
    auto bm = boruvka(g);

    assert_true(bm.is_forest);
    assert_false(is_spanning_tree(g, bm));
    assert_eq(bm.edges.size(), static_cast<size_t>(4));
    assert_near(bm.total_weight, 10.0, 1e-9);
    assert_near(bm.total_weight, km.total_weight, 1e-9);
}

