    auto g = make_graph(7);
    g.add_edge(0, 1, 4.0);
    g.add_edge(0, 2, 3.0);
    g.add_edge(0, 3, 8.0);
    g.add_edge(1, 2, 2.0);
    g.add_edge(1, 4, 6.0);
    g.add_edge(2, 3, 5.0);
    g.add_edge(2, 4, 7.0);
    g.add_edge(3, 5, 1.0);
    g.add_edge(4, 5, 9.0);
    g.add_edge(4, 6, 2.0);
    g.add_edge(5, 6, 3.0);

    assert_connected_mst_parity(g);
}

